        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (int[] edge : redEdges) {
            graph.get(edge[0]).add(edge[1]);
        }
        for (int[] edge : blueEdges) {
            graph.get(edge[0]).add(edge[1]);
        }
        int[] answer = new int[n];
        boolean[][] visited = new boolean[n][2];
        for (int i = 0; i < n; i++) {
            if (dfs(graph, i, 0, visited, answer)) {
                answer[i] = 1;
            } else {
                answer[i] = -1;
            }
        }
        return answer;
    }
    private boolean dfs(List<List<Integer>> graph, int node, int color, boolean[][] visited, int[] answer) {
        if (visited[node][color]) {
            return false;
        }
        visited[node][color] = true;
        if (node == 0) {
            answer[0] = 1;
            return true;
        }
        for (int neighbor : graph.get(node)) {
            if ((color == 0 && !graph.get(neighbor).contains(node)) || (color == 1 && graph.get(neighbor).contains(node))) {
                if (dfs(graph, neighbor, 1 - color, visited, answer)) {
                    answer[node] = answer[0] + 1;
                    return true;
                }
            }
        }
        return false;
    }
}
